export default {
  async fetch(request, env, ctx) {
    const requestId = crypto.randomUUID();
    try {
      const url = new URL(request.url);

      if (request.method === "OPTIONS") {
        return corsResponse(null, 204, request);
      }

      if (url.pathname === "/health") {
        return corsResponse(
          JSON.stringify({
            ok: true,
            service: "worker",
            requestId,
            timestamp: new Date().toISOString()
          }),
          200,
          request
        );
      }

      const authResult = authenticateRequest(request, env);
      if (!authResult.ok) {
        return corsResponse(
          JSON.stringify({
            ok: false,
            error: authResult.error,
            requestId
          }),
          authResult.status,
          request
        );
      }

      if (url.pathname === "/send-email" && request.method === "POST") {
        const body = await parseJson(request);
        if (!body.ok) {
          return corsResponse(
            JSON.stringify({
              ok: false,
              error: body.error,
              requestId
            }),
            400,
            request
          );
        }

        const { to, subject, text, html, from } = body.data;
        if (!to || !subject || (!text && !html)) {
          return corsResponse(
            JSON.stringify({
              ok: false,
              error: "Missing required fields: to, subject, and text or html",
              requestId
            }),
            400,
            request
          );
        }

        const sendGridResponse = await sendEmailViaSendGrid({
          apiKey: env.SENDGRID_API_KEY,
          to,
          subject,
          text,
          html,
          from: from || env.SENDGRID_FROM_EMAIL
        });

        return corsResponse(
          JSON.stringify({
            ok: true,
            requestId,
            provider: "sendgrid",
            result: sendGridResponse
          }),
          200,
          request
        );
      }

      if (url.pathname === "/create-payment-intent" && request.method === "POST") {
        const body = await parseJson(request);
        if (!body.ok) {
          return corsResponse(
            JSON.stringify({
              ok: false,
              error: body.error,
              requestId
            }),
            400,
            request
          );
        }

        const { amount, currency = "usd", metadata = {} } = body.data;
        if (!amount || typeof amount !== "number" || amount <= 0) {
          return corsResponse(
            JSON.stringify({
              ok: false,
              error: "Missing or invalid required field: amount",
              requestId
            }),
            400,
            request
          );
        }

        const stripeResponse = await createPaymentIntent({
          secretKey: env.STRIPE_SECRET_KEY,
          amount,
          currency,
          metadata
        });

        return corsResponse(
          JSON.stringify({
            ok: true,
            requestId,
            provider: "stripe",
            result: stripeResponse
          }),
          200,
          request
        );
      }

      return corsResponse(
        JSON.stringify({
          ok: false,
          error: "Not found",
          requestId
        }),
        404,
        request
      );
    } catch (error) {
      return corsResponse(
        JSON.stringify({
          ok: false,
          error: "Internal server error",
          requestId
        }),
        500,
        request
      );
    }
  }
};

function corsResponse(body, status = 200, request) {
  const headers = new Headers({
    "content-type": "application/json; charset=utf-8",
    "access-control-allow-origin": request?.headers.get("origin") || "*",
    "access-control-allow-methods": "GET,POST,OPTIONS",
    "access-control-allow-headers": "content-type,authorization,x-api-key",
    "access-control-max-age": "86400"
  });
  return new Response(body, { status, headers });
}

function authenticateRequest(request, env) {
  const expectedApiKey = env.API_KEY;
  if (!expectedApiKey) {
    return { ok: false, status: 500, error: "Server authentication not configured" };
  }

  const authHeader = request.headers.get("authorization");
  const apiKeyHeader = request.headers.get("x-api-key");
  const provided = authHeader?.startsWith("Bearer ") ? authHeader.slice(7).trim() : apiKeyHeader?.trim();

  if (!provided) {
    return { ok: false, status: 401, error: "Missing authentication" };
  }

  if (provided !== expectedApiKey) {
    return { ok: false, status: 403, error: "Invalid authentication" };
  }

  return { ok: true };
}

async function parseJson(request) {
  try {
    const data = await request.json();
    if (!data || typeof data !== "object" || Array.isArray(data)) {
      return { ok: false, error: "Invalid JSON body" };
    }
    return { ok: true, data };
  } catch {
    return { ok: false, error: "Invalid JSON body" };
  }
}

async function sendEmailViaSendGrid({ apiKey, to, subject, text, html, from }) {
  if (!apiKey) throw new Error("SendGrid API key missing");
  if (!from) throw new Error("SendGrid from email missing");

  const payload = {
    personalizations: [{ to: [{ email: to }] }],
    from: { email: from },
    subject,
    content: []
  };

  if (text) payload.content.push({ type: "text/plain", value: text });
  if (html) payload.content.push({ type: "text/html", value: html });

  const response = await fetch("https://api.sendgrid.com/v3/mail/send", {
    method: "POST",
    headers: {
      authorization: `Bearer ${apiKey}`,
      "content-type": "application/json"
    },
    body: JSON.stringify(payload)
  });

  if (!response.ok) {
    const errorText = await safeText(response);
    throw new Error(`SendGrid error: ${response.status} ${errorText}`);
  }

  return { message: "Email sent" };
}

async function createPaymentIntent({ secretKey, amount, currency, metadata }) {
  if (!secretKey) throw new Error("Stripe secret key missing");

  const form = new URLSearchParams();
  form.set("amount", String(Math.round(amount)));
  form.set("currency", currency);
  for (const [key, value] of Object.entries(metadata || {})) {
    form.set(`metadata[${key}]`, String(value));
  }

  const response = await fetch("https://api.stripe.com/v1/payment_intents", {
    method: "POST",
    headers: {
      authorization: `Bearer ${secretKey}`,
      "content-type": "application/x-www-form-urlencoded"
    },
    body: form.toString()
  });

  const data = await response.json().catch(() => null);

  if (!response.ok) {
    const message = data?.error?.message || "Stripe request failed";
    throw new Error(`Stripe error: ${response.status} ${message}`);
  }

  return {
    id: data.id,
    client_secret: data.client_secret,
    status: data.status,
    amount: data.amount,
    currency: data.currency
  };
}

async function safeText(response) {
  try {
    return await response.text();
  } catch {
    return "";
  }
}